using Microsoft.AspNetCore.Authorization;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Get all shipments (dispatchers)
        group.MapGet("/", [Authorize(Roles = "Dispatcher")] async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery,
                    CustomerEmail = s.CustomerEmail,
                    Description = s.Description
                })
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // Get shipments for current customer
        group.MapGet("/my", async (HttpContext context, ApplicationDbContext db) =>
        {
            var email = context.User.Identity?.Name ?? string.Empty;
            var shipments = await db.Shipments
                .Where(s => s.CustomerEmail == email)
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery,
                    CustomerEmail = s.CustomerEmail,
                    Description = s.Description
                })
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // Track by tracking number (customer)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .Where(s => s.TrackingNumber == trackingNumber)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery,
                    CustomerEmail = s.CustomerEmail,
                    Description = s.Description
                })
                .FirstOrDefaultAsync();

            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        // Create shipment (dispatcher)
        group.MapPost("/", [Authorize(Roles = "Dispatcher")] async (ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = dto.TrackingNumber,
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = dto.Status,
                ShippedDate = dto.ShippedDate,
                EstimatedDelivery = dto.EstimatedDelivery,
                CustomerEmail = dto.CustomerEmail,
                Description = dto.Description
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();

            dto.Id = shipment.Id;
            return Results.Created($"/api/shipments/{shipment.Id}", dto);
        });

        // Update shipment status (dispatcher)
        group.MapPut("/{id}", [Authorize(Roles = "Dispatcher")] async (int id, ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = dto.Status;
            shipment.Destination = dto.Destination;
            shipment.EstimatedDelivery = dto.EstimatedDelivery;
            shipment.Description = dto.Description;

            await db.SaveChangesAsync();
            return Results.NoContent();
        });
    }
}

using Microsoft.AspNetCore.Identity;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker;

public static class SeedData
{
    public static async Task InitializeAsync(IServiceProvider serviceProvider)
    {
        using var scope = serviceProvider.CreateScope();
        var roleManager = scope.ServiceProvider.GetRequiredService<RoleManager<IdentityRole>>();
        var userManager = scope.ServiceProvider.GetRequiredService<UserManager<ApplicationUser>>();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();

        // Create roles
        string[] roles = ["Dispatcher", "Customer"];
        foreach (var role in roles)
        {
            if (!await roleManager.RoleExistsAsync(role))
            {
                await roleManager.CreateAsync(new IdentityRole(role));
            }
        }

        // Create demo dispatcher
        var dispatcher = await userManager.FindByEmailAsync("dispatcher@shiptrack.com");
        if (dispatcher is null)
        {
            dispatcher = new ApplicationUser
            {
                UserName = "dispatcher@shiptrack.com",
                Email = "dispatcher@shiptrack.com",
                EmailConfirmed = true
            };
            await userManager.CreateAsync(dispatcher, "Dispatch1!");
            await userManager.AddToRoleAsync(dispatcher, "Dispatcher");
        }

        // Create demo customer
        var customer = await userManager.FindByEmailAsync("customer@example.com");
        if (customer is null)
        {
            customer = new ApplicationUser
            {
                UserName = "customer@example.com",
                Email = "customer@example.com",
                EmailConfirmed = true
            };
            await userManager.CreateAsync(customer, "Customer1!");
            await userManager.AddToRoleAsync(customer, "Customer");
        }

        // Seed shipments
        if (!db.Shipments.Any())
        {
            db.Shipments.AddRange(
                new Shipment
                {
                    TrackingNumber = "SHT-2026-001",
                    Origin = "New York, NY",
                    Destination = "Los Angeles, CA",
                    Status = ShipmentStatus.InTransit,
                    ShippedDate = DateTime.UtcNow.AddDays(-3),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(2),
                    CustomerEmail = "customer@example.com",
                    Description = "Electronics - 2 packages"
                },
                new Shipment
                {
                    TrackingNumber = "SHT-2026-002",
                    Origin = "Chicago, IL",
                    Destination = "Miami, FL",
                    Status = ShipmentStatus.PickedUp,
                    ShippedDate = DateTime.UtcNow.AddDays(-1),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(4),
                    CustomerEmail = "customer@example.com",
                    Description = "Furniture - 1 crate"
                },
                new Shipment
                {
                    TrackingNumber = "SHT-2026-003",
                    Origin = "Seattle, WA",
                    Destination = "Denver, CO",
                    Status = ShipmentStatus.Delivered,
                    ShippedDate = DateTime.UtcNow.AddDays(-7),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(-2),
                    CustomerEmail = "other@example.com",
                    Description = "Auto parts - 5 boxes"
                },
                new Shipment
                {
                    TrackingNumber = "SHT-2026-004",
                    Origin = "Houston, TX",
                    Destination = "Phoenix, AZ",
                    Status = ShipmentStatus.Delayed,
                    ShippedDate = DateTime.UtcNow.AddDays(-5),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(1),
                    CustomerEmail = "other@example.com",
                    Description = "Medical supplies - fragile"
                },
                new Shipment
                {
                    TrackingNumber = "SHT-2026-005",
                    Origin = "Boston, MA",
                    Destination = "Atlanta, GA",
                    Status = ShipmentStatus.OutForDelivery,
                    ShippedDate = DateTime.UtcNow.AddDays(-4),
                    EstimatedDelivery = DateTime.UtcNow,
                    CustomerEmail = "customer@example.com",
                    Description = "Books - 3 cartons"
                }
            );
            await db.SaveChangesAsync();
        }
    }
}

