arguments.file_text:
@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize(Roles = "Dispatcher")]
@rendermode InteractiveAuto
@inject HttpClient Http

<PageTitle>Shipment Dashboard</PageTitle>

<h1>Shipment Dashboard</h1>

<div class="mb-3">
    <button class="btn btn-primary" @onclick="ShowCreateForm">
        <span class="bi bi-plus"></span> New Shipment
    </button>
    <button class="btn btn-outline-secondary ms-2" @onclick="LoadShipments">
        Refresh
    </button>
</div>

@if (showCreate)
{
    <div class="card mb-4">
        <div class="card-header">Create New Shipment</div>
        <div class="card-body">
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="CreateShipment">
                <DataAnnotationsValidator />
                <div class="row g-3">
                    <div class="col-md-4">
                        <label class="form-label">Tracking Number</label>
                        <InputText @bind-Value="newShipment.TrackingNumber" class="form-control" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Origin</label>
                        <InputText @bind-Value="newShipment.Origin" class="form-control" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Destination</label>
                        <InputText @bind-Value="newShipment.Destination" class="form-control" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Customer Email</label>
                        <InputText @bind-Value="newShipment.CustomerEmail" class="form-control" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Description</label>
                        <InputText @bind-Value="newShipment.Description" class="form-control" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Estimated Delivery</label>
                        <InputDate @bind-Value="newShipment.EstimatedDelivery" class="form-control" />
                    </div>
                </div>
                <div class="mt-3">
                    <button type="submit" class="btn btn-success">Create</button>
                    <button type="button" class="btn btn-secondary ms-2" @onclick="() => showCreate = false">Cancel</button>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!shipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Filter by tracking #, destination, or customer..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Customer</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><strong>@shipment.TrackingNumber</strong></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">
                                @shipment.Status
                            </span>
                        </td>
                        <td>@shipment.CustomerEmail</td>
                        <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm d-inline-block w-auto"
                                    value="@((int)shipment.Status)"
                                    @onchange="e => UpdateStatus(shipment, e)">
                                @foreach (ShipmentStatus status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@((int)status)">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private ShipmentDto newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(5), ShippedDate = DateTime.UtcNow };
    private bool showCreate;
    private string filterText = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.CustomerEmail.Contains(filterText, StringComparison.OrdinalIgnoreCase)
        ) ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments");
    }

    private void ShowCreateForm()
    {
        newShipment = new ShipmentDto
        {
            TrackingNumber = $"SHT-{DateTime.UtcNow:yyyy}-{Random.Shared.Next(100, 999)}",
            EstimatedDelivery = DateTime.UtcNow.AddDays(5),
            ShippedDate = DateTime.UtcNow
        };
        showCreate = true;
    }

    private async Task CreateShipment()
    {
        var response = await Http.PostAsJsonAsync("api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            showCreate = false;
            await LoadShipments();
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var statusValue))
        {
            shipment.Status = (ShipmentStatus)statusValue;
            await Http.PutAsJsonAsync($"api/shipments/{shipment.Id}", shipment);
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/tracking"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize]
@rendermode InteractiveAuto
@inject HttpClient Http

<PageTitle>Track My Shipments</PageTitle>

<h1>Track Shipments</h1>

<div class="row mb-4">
    <div class="col-md-8">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHT-2026-001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment">Track</button>
        </div>
    </div>
</div>

@if (trackingError)
{
    <div class="alert alert-warning">Shipment not found. Please check your tracking number.</div>
}

@if (trackedShipment is not null)
{
    <div class="card mb-4">
        <div class="card-header bg-primary text-white">
            <h5 class="mb-0">Tracking: @trackedShipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>From:</strong> @trackedShipment.Origin</p>
                    <p><strong>To:</strong> @trackedShipment.Destination</p>
                    <p><strong>Description:</strong> @trackedShipment.Description</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Status:</strong>
                        <span class="badge @GetStatusBadgeClass(trackedShipment.Status) fs-6">
                            @trackedShipment.Status
                        </span>
                    </p>
                    <p><strong>Shipped:</strong> @trackedShipment.ShippedDate.ToString("MMMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong>
                        <span class="@(trackedShipment.EstimatedDelivery < DateTime.UtcNow && trackedShipment.Status != ShipmentStatus.Delivered ? "text-danger fw-bold" : "")">
                            @trackedShipment.EstimatedDelivery.ToString("MMMM dd, yyyy")
                        </span>
                    </p>
                </div>
            </div>

            <!-- Progress visualization -->
            <div class="mt-3">
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar @GetProgressBarClass(trackedShipment.Status)"
                         role="progressbar"
                         style="width: @GetProgressPercent(trackedShipment.Status)%"
                         aria-valuenow="@GetProgressPercent(trackedShipment.Status)"
                         aria-valuemin="0" aria-valuemax="100">
                        @trackedShipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

<hr />

<h3>My Shipments</h3>
@if (myShipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (!myShipments.Any())
{
    <p>You have no shipments on record.</p>
}
else
{
    <div class="row">
        @foreach (var shipment in myShipments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100 @(shipment.Status == ShipmentStatus.Delayed ? "border-danger" : "")">
                    <div class="card-body">
                        <h6 class="card-title">@shipment.TrackingNumber</h6>
                        <p class="card-text mb-1">
                            <small class="text-muted">@shipment.Origin → @shipment.Destination</small>
                        </p>
                        <p class="card-text mb-1">@shipment.Description</p>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
                    </div>
                    <div class="card-footer text-muted">
                        <small>Est. delivery: @shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</small>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<ShipmentDto>? myShipments;
    private ShipmentDto? trackedShipment;
    private string trackingNumber = string.Empty;
    private bool trackingError;

    protected override async Task OnInitializedAsync()
    {
        myShipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments/my");
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await TrackShipment();
        }
    }

    private async Task TrackShipment()
    {
        trackingError = false;
        trackedShipment = null;

        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        try
        {
            trackedShipment = await Http.GetFromJsonAsync<ShipmentDto>($"api/shipments/track/{trackingNumber.Trim()}");
        }
        catch (HttpRequestException)
        {
            trackingError = true;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        _ => 0
    };
}

