@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize(Roles = "Dispatcher")]
@rendermode InteractiveAuto
@inject HttpClient Http

<PageTitle>Shipment Dashboard</PageTitle>

<h1>Shipment Dashboard</h1>

<div class="mb-3">
    <button class="btn btn-primary" @onclick="ShowCreateForm">
        <span class="bi bi-plus"></span> New Shipment
    </button>
    <button class="btn btn-outline-secondary ms-2" @onclick="LoadShipments">
        Refresh
    </button>
</div>

@if (showCreate)
{
    <div class="card mb-4">
        <div class="card-header">Create New Shipment</div>
        <div class="card-body">
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="CreateShipment">
                <DataAnnotationsValidator />
                <div class="row g-3">
                    <div class="col-md-4">
                        <label class="form-label">Tracking Number</label>
                        <InputText @bind-Value="newShipment.TrackingNumber" class="form-control" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Origin</label>
                        <InputText @bind-Value="newShipment.Origin" class="form-control" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Destination</label>
                        <InputText @bind-Value="newShipment.Destination" class="form-control" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Customer Email</label>
                        <InputText @bind-Value="newShipment.CustomerEmail" class="form-control" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Description</label>
                        <InputText @bind-Value="newShipment.Description" class="form-control" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Estimated Delivery</label>
                        <InputDate @bind-Value="newShipment.EstimatedDelivery" class="form-control" />
                    </div>
                </div>
                <div class="mt-3">
                    <button type="submit" class="btn btn-success">Create</button>
                    <button type="button" class="btn btn-secondary ms-2" @onclick="() => showCreate = false">Cancel</button>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!shipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Filter by tracking #, destination, or customer..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Customer</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><strong>@shipment.TrackingNumber</strong></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">
                                @shipment.Status
                            </span>
                        </td>
                        <td>@shipment.CustomerEmail</td>
                        <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm d-inline-block w-auto"
                                    value="@((int)shipment.Status)"
                                    @onchange="e => UpdateStatus(shipment, e)">
                                @foreach (ShipmentStatus status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@((int)status)">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private ShipmentDto newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(5), ShippedDate = DateTime.UtcNow };
    private bool showCreate;
    private string filterText = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.CustomerEmail.Contains(filterText, StringComparison.OrdinalIgnoreCase)
        ) ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments");
    }

    private void ShowCreateForm()
    {
        newShipment = new ShipmentDto
        {
            TrackingNumber = $"SHT-{DateTime.UtcNow:yyyy}-{Random.Shared.Next(100, 999)}",
            EstimatedDelivery = DateTime.UtcNow.AddDays(5),
            ShippedDate = DateTime.UtcNow
        };
        showCreate = true;
    }

    private async Task CreateShipment()
    {
        var response = await Http.PostAsJsonAsync("api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            showCreate = false;
            await LoadShipments();
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var statusValue))
        {
            shipment.Status = (ShipmentStatus)statusValue;
            await Http.PutAsJsonAsync($"api/shipments/{shipment.Id}", shipment);
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

